"""Render the committed static entrypoint ``_dagger_main.py``.

Pure string generation from a live ``Module``: embeds the serialized
ModuleTypes JSON (with all values resolved at generate time) so the runtime
def phase replays it without any analysis — the Python analog of the Go
SDK's generated ``invoke()`` def arm.
"""

from __future__ import annotations

import json
import typing

from dagger.mod._introspect.serialize import live_to_introspection_json

if typing.TYPE_CHECKING:
    from dagger.mod._module import Module

_TEMPLATE = '''\
"""Generated by `dagger develop` — do not edit.

Static module entrypoint. The def phase replays the pre-serialized
TypeDefs below (no source analysis at runtime).
"""
# ruff: noqa
from __future__ import annotations

import json

from dagger.mod._introspect._runtime import typedefs_from_json

MODULE_NAME = {module_name!r}
MAIN_OBJECT = {main_object!r}
MODULE_TYPES = json.loads({types_json!r})


async def typedefs():
    """Return the module's pre-computed TypeDefs (def phase)."""
    return await typedefs_from_json(MODULE_TYPES)
'''


def render_entrypoint(
    module: Module,
    *,
    main_object_name: str,
    module_name: str,
) -> str:
    """Return the source of the generated ``_dagger_main.py``."""
    response = live_to_introspection_json(
        module,
        main_object_name=main_object_name,
        module_name=module_name,
    )
    return _TEMPLATE.format(
        module_name=module_name,
        main_object=main_object_name,
        types_json=json.dumps(response),
    )
